Your login endpoint is vulnerable to brute force and credential stuffing attacks without rate limiting. Attackers can make unlimited login attempts, testing thousands of password combinations or stolen credentials per second.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');
const { Pool } = require('pg');

const app = express();
app.use(express.json());

const pool = new Pool({
  connectionString: process.env.DATABASE_URL
});

// VULNERABLE: No rate limiting on authentication endpoint
app.post('/api/login', async (req, res) => {
  const { email, password } = req.body;

  try {
    const result = await pool.query(
      'SELECT id, email, password_hash FROM users WHERE email = $1',
      [email]
    );

    if (result.rows.length === 0) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const user = result.rows[0];
    const validPassword = await bcrypt.compare(password, user.password_hash);

    if (!validPassword) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const token = jwt.sign({ userId: user.id }, process.env.JWT_SECRET, {
      expiresIn: '24h'
    });

    res.json({ token });
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```bash
# Credential stuffing attack using hydra
hydra -L emails.txt -P passwords.txt https://target.com/api/login http-post-form "/api/login:email=^USER^&password=^PASS^:Invalid credentials"

# Or simple brute force with curl loop
for pass in $(cat rockyou.txt); do
  curl -s -X POST https://target.com/api/login \
    -H "Content-Type: application/json" \
    -d "{\"email\":\"victim@company.com\",\"password\":\"$pass\"}"
done
```

**Why This Is Dangerous**:
- Attackers can test millions of credentials against your endpoint without restriction
- Credential stuffing attacks use leaked password databases (billions of credentials available)
- No detection or blocking mechanism for suspicious activity
- bcrypt provides no protection if attacker can make unlimited attempts
- Database and server resources can be exhausted (DoS)

**SECURE VERSION**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');
const { Pool } = require('pg');
const rateLimit = require('express-rate-limit');
const RedisStore = require('rate-limit-redis');
const Redis = require('ioredis');
const winston = require('winston');

const app = express();
app.use(express.json());

const redis = new Redis(process.env.REDIS_URL);
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

// Configure logging for security events
const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [new winston.transports.File({ filename: 'security.log' })]
});

// SECURE: Rate limiting by IP address
const loginLimiter = rateLimit({
  store: new RedisStore({ sendCommand: (...args) => redis.call(...args) }),
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // 5 attempts per window
  message: { error: 'Too many login attempts, please try again later' },
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res, next, options) => {
    securityLogger.warn({
      event: 'rate_limit_exceeded',
      ip: req.ip,
      email: req.body.email,
      timestamp: new Date().toISOString()
    });
    res.status(options.statusCode).json(options.message);
  }
});

app.post('/api/login', loginLimiter, async (req, res) => {
  const { email, password } = req.body;

  try {
    const result = await pool.query(
      'SELECT id, email, password_hash FROM users WHERE email = $1',
      [email]
    );

    // Use constant-time comparison to prevent timing attacks
    if (result.rows.length === 0) {
      await bcrypt.compare(password, '$2b$10$invalidhashfortimingattackprevention');
      securityLogger.info({ event: 'login_failed', reason: 'unknown_email', ip: req.ip });
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const user = result.rows[0];
    const validPassword = await bcrypt.compare(password, user.password_hash);

    if (!validPassword) {
      securityLogger.info({ event: 'login_failed', reason: 'wrong_password', email, ip: req.ip });
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    securityLogger.info({ event: 'login_success', userId: user.id, ip: req.ip });

    const token = jwt.sign({ userId: user.id }, process.env.JWT_SECRET, {
      expiresIn: '24h'
    });

    res.json({ token });
  } catch (error) {
    securityLogger.error({ event: 'login_error', error: error.message, ip: req.ip });
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Rate limiting by IP**: Maximum 5 login attempts per 15 minutes per IP address
- **Redis-backed store**: Distributed rate limiting works across multiple server instances
- **Security logging**: All authentication events logged for monitoring and forensics
- **Timing attack prevention**: Constant-time operations even for non-existent users

Excellent point. Sophisticated attackers use rotating proxies, botnets, and residential IP services to bypass IP-based rate limiting. You need multi-layered protection including per-account rate limiting, device fingerprinting, anomaly detection, and progressive security escalation.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');
const { Pool } = require('pg');
const Redis = require('ioredis');
const winston = require('winston');
const { v4: uuidv4 } = require('uuid');
const geoip = require('geoip-lite');

const app = express();
app.use(express.json());
app.set('trust proxy', true);

const redis = new Redis(process.env.REDIS_URL);
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security.log' }),
    new winston.transports.Http({ host: 'siem.company.com', port: 8080 })
  ]
});

// Multi-layer rate limiting configuration
const RATE_LIMITS = {
  IP_WINDOW: 15 * 60,           // 15 minutes
  IP_MAX_ATTEMPTS: 10,          // Per IP
  ACCOUNT_WINDOW: 60 * 60,      // 1 hour  
  ACCOUNT_MAX_ATTEMPTS: 5,      // Per account
  GLOBAL_WINDOW: 60,            // 1 minute
  GLOBAL_MAX_ATTEMPTS: 1000,    // Total system-wide
  LOCKOUT_DURATION: 30 * 60,    // 30 minute lockout
  CAPTCHA_THRESHOLD: 3          // Show CAPTCHA after 3 failures
};

// Extract device fingerprint from request
function getDeviceFingerprint(req) {
  const components = [
    req.headers['user-agent'] || '',
    req.headers['accept-language'] || '',
    req.headers['accept-encoding'] || '',
    req.ip
  ];
  return require('crypto').createHash('sha256')
    .update(components.join('|'))
    .digest('hex').substring(0, 16);
}

// Check for anomalous login patterns
async function detectAnomalies(email, req) {
  const anomalies = [];
  const geo = geoip.lookup(req.ip);
  const currentCountry = geo?.country || 'UNKNOWN';

  // Check last successful login location
  const lastLogin = await redis.hgetall(`user:lastlogin:${email}`);
  if (lastLogin.country && lastLogin.country !== currentCountry) {
    const timeSinceLastLogin = Date.now() - parseInt(lastLogin.timestamp || 0);
    // Impossible travel detection (e.g., different country within 2 hours)
    if (timeSinceLastLogin < 2 * 60 * 60 * 1000) {
      anomalies.push('impossible_travel');
    }
  }

  // Check for credential stuffing patterns (many accounts, same IP)
  const accountsFromIP = await redis.scard(`ip:accounts:${req.ip}`);
  if (accountsFromIP > 10) {
    anomalies.push('multiple_accounts_same_ip');
  }

  // Check for distributed attack (same account, many IPs)
  const ipsForAccount = await redis.scard(`account:ips:${email}`);
  if (ipsForAccount > 5) {
    anomalies.push('distributed_attack_pattern');
  }

  return anomalies;
}

// Multi-layer rate limit check
async function checkRateLimits(email, req) {
  const ip = req.ip;
  const deviceId = getDeviceFingerprint(req);
  const now = Math.floor(Date.now() / 1000);

  // Layer 1: Global rate limit (protect infrastructure)
  const globalKey = `ratelimit:global:${Math.floor(now / RATE_LIMITS.GLOBAL_WINDOW)}`;
  const globalCount = await redis.incr(globalKey);
  await redis.expire(globalKey, RATE_LIMITS.GLOBAL_WINDOW);
  if (globalCount > RATE_LIMITS.GLOBAL_MAX_ATTEMPTS) {
    return { blocked: true, reason: 'system_overload', retryAfter: RATE_LIMITS.GLOBAL_WINDOW };
  }

  // Layer 2: IP-based rate limit
  const ipKey = `ratelimit:ip:${ip}`;
  const ipCount = await redis.incr(ipKey);
  await redis.expire(ipKey, RATE_LIMITS.IP_WINDOW);
  if (ipCount > RATE_LIMITS.IP_MAX_ATTEMPTS) {
    return { blocked: true, reason: 'ip_rate_limit', retryAfter: RATE_LIMITS.IP_WINDOW };
  }

  // Layer 3: Account-based rate limit (stops distributed attacks)
  const accountKey = `ratelimit:account:${email}`;
  const accountCount = await redis.incr(accountKey);
  await redis.expire(accountKey, RATE_LIMITS.ACCOUNT_WINDOW);
  if (accountCount > RATE_LIMITS.ACCOUNT_MAX_ATTEMPTS) {
    // Trigger account lockout
    await redis.setex(`lockout:${email}`, RATE_LIMITS.LOCKOUT_DURATION, 'locked');
    return { blocked: true, reason: 'account_locked', retryAfter: RATE_LIMITS.LOCKOUT_DURATION };
  }

  // Layer 4: Device fingerprint rate limit
  const deviceKey = `ratelimit:device:${deviceId}`;
  const deviceCount = await redis.incr(deviceKey);
  await redis.expire(deviceKey, RATE_LIMITS.IP_WINDOW);

  // Track IPs per account and accounts per IP for anomaly detection
  await redis.sadd(`account:ips:${email}`, ip);
  await redis.expire(`account:ips:${email}`, 3600);
  await redis.sadd(`ip:accounts:${ip}`, email);
  await redis.expire(`ip:accounts:${ip}`, 3600);

  return {
    blocked: false,
    requireCaptcha: accountCount >= RATE_LIMITS.CAPTCHA_THRESHOLD,
    attemptNumber: accountCount
  };
}

// Verify CAPTCHA token (integrate with reCAPTCHA, hCaptcha, etc.)
async function verifyCaptcha(token) {
  if (!token) return false;
  // Integration with CAPTCHA provider
  const response = await fetch('https://www.google.com/recaptcha/api/siteverify', {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: `secret=${process.env.RECAPTCHA_SECRET}&response=${token}`
  });
  const data = await response.json();
  return data.success && data.score >= 0.5;
}

app.post('/api/login', async (req, res) => {
  const { email, password, captchaToken } = req.body;
  const requestId = uuidv4();
  const startTime = Date.now();

  // Input validation
  if (!email || !password || typeof email !== 'string' || typeof password !== 'string') {
    return res.status(400).json({ error: 'Invalid request format' });
  }

  const normalizedEmail = email.toLowerCase().trim();

  try {
    // Check if account is locked out
    const isLocked = await redis.get(`lockout:${normalizedEmail}`);
    if (isLocked) {
      const ttl = await redis.ttl(`lockout:${normalizedEmail}`);
      securityLogger.warn({
        requestId, event: 'login_blocked', reason: 'account_locked',
        email: normalizedEmail, ip: req.ip
      });
      return res.status(429).json({
        error: 'Account temporarily locked due to multiple failed attempts',
        retryAfter: ttl
      });
    }

    // Multi-layer rate limit check
    const rateLimitResult = await checkRateLimits(normalizedEmail, req);
    if (rateLimitResult.blocked) {
      securityLogger.warn({
        requestId, event: 'rate_limit_blocked', reason: rateLimitResult.reason,
        email: normalizedEmail, ip: req.ip, retryAfter: rateLimitResult.retryAfter
      });
      return res.status(429).json({
        error: 'Too many attempts, please try again later',
        retryAfter: rateLimitResult.retryAfter
      });
    }

    // Require CAPTCHA after threshold
    if (rateLimitResult.requireCaptcha) {
      const captchaValid = await verifyCaptcha(captchaToken);
      if (!captchaValid) {
        return res.status(428).json({
          error: 'CAPTCHA verification required',
          requireCaptcha: true
        });
      }
    }

    // Detect anomalies
    const anomalies = await detectAnomalies(normalizedEmail, req);
    if (anomalies.length > 0) {
      securityLogger.warn({
        requestId, event: 'anomaly_detected', anomalies,
        email: normalizedEmail, ip: req.ip
      });
      // Could trigger additional verification (MFA, email confirmation)
    }

    // Perform authentication
    const result = await pool.query(
      'SELECT id, email, password_hash, mfa_enabled FROM users WHERE email = $1',
      [normalizedEmail]
    );

    // Constant-time response for non-existent users
    if (result.rows.length === 0) {
      await bcrypt.compare(password, '$2b$10$XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX');
      await recordFailedAttempt(normalizedEmail, req, requestId, 'unknown_user');
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const user = result.rows[0];
    const validPassword = await bcrypt.compare(password, user.password_hash);

    if (!validPassword) {
      await recordFailedAttempt(normalizedEmail, req, requestId, 'wrong_password');
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Clear rate limit counters on successful login
    await redis.del(`ratelimit:account:${normalizedEmail}`);
    await redis.del(`account:ips:${normalizedEmail}`);

    // Record successful login for anomaly detection
    const geo = geoip.lookup(req.ip);
    await redis.hset(`user:lastlogin:${normalizedEmail}`, {
      timestamp: Date.now().toString(),
      ip: req.ip,
      country: geo?.country || 'UNKNOWN'
    });

    securityLogger.info({
      requestId, event: 'login_success', userId: user.id,
      ip: req.ip, duration: Date.now() - startTime,
      anomalies: anomalies.length > 0 ? anomalies : undefined
    });

    const token = jwt.sign(
      { userId: user.id, sessionId: uuidv4() },
      process.env.JWT_SECRET,
      { expiresIn: '24h', algorithm: 'HS256' }
    );

    res.json({ token, requireMfa: user.mfa_enabled });

  } catch (error) {
    securityLogger.error({
      requestId, event: 'login_error', error: error.message, ip: req.ip
    });
    res.status(500).json({ error: 'Internal server error' });
  }
});

async function recordFailedAttempt(email, req, requestId, reason) {
  securityLogger.info({
    requestId, event: 'login_failed', reason,
    email, ip: req.ip, userAgent: req.headers['user-agent']
  });
}

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Global Rate Limiting**: Protects infrastructure from being overwhelmed, caps total login attempts system-wide
```javascript
const globalCount = await redis.incr(`ratelimit:global:${timeWindow}`);
if (globalCount > 1000) return { blocked: true, reason: 'system_overload' };
```

2. **Account-Based Rate Limiting**: Stops distributed attacks by limiting attempts per account regardless of IP
```javascript
const accountCount = await redis.incr(`ratelimit:account:${email}`);
if (accountCount > 5) await redis.setex(`lockout:${email}`, 1800, 'locked');
```

3. **Anomaly Detection**: Identifies suspicious patterns like impossible travel or credential stuffing
```javascript
if (lastCountry !== currentCountry && timeSinceLastLogin < 2 * 60 * 60 * 1000) {
  anomalies.push('impossible_travel');
}
```

**Additional Protections**:
- **Progressive CAPTCHA**: Only shown after multiple failures, reducing friction for legitimate users
- **Device fingerprinting**: Tracks and limits requests from suspicious device signatures
- **Timing attack prevention**: Constant-time operations for both valid and invalid emails
- **SIEM integration**: Real-time alerting on attack patterns via security logging
- **Account lockout with exponential backoff**: Increases lockout duration on repeated attacks
- **Geo-velocity checking**: Detects physically impossible login location changes

