**Why This Is Dangerous**:
- Attackers can attempt millions of password combinations
- Credential stuffing attacks use leaked password databases (billions of credentials available)
- bcrypt is CPU-intensive; unlimited requests cause DoS
- No visibility into attack patterns or failed attempts

**SECURE VERSION**:

```go
package main

import (
	"database/sql"
	"encoding/json"
	"log"
	"net/http"
	"sync"
	"time"

	"golang.org/x/crypto/bcrypt"
	"golang.org/x/time/rate"
	_ "github.com/lib/pq"
)

type LoginRequest struct {
	Username string `json:"username"`
	Password string `json:"password"`
}

type LoginResponse struct {
	Token   string `json:"token,omitempty"`
	Message string `json:"message"`
}

var db *sql.DB

// Rate limiter per IP address
type IPRateLimiter struct {
	ips map[string]*rate.Limiter
	mu  *sync.RWMutex
	r   rate.Limit
	b   int
}

func NewIPRateLimiter(r rate.Limit, b int) *IPRateLimiter {
	return &IPRateLimiter{
		ips: make(map[string]*rate.Limiter),
		mu:  &sync.RWMutex{},
		r:   r,
		b:   b,
	}
}

func (i *IPRateLimiter) GetLimiter(ip string) *rate.Limiter {
	i.mu.Lock()
	defer i.mu.Unlock()

	limiter, exists := i.ips[ip]
	if !exists {
		limiter = rate.NewLimiter(i.r, i.b)
		i.ips[ip] = limiter
	}
	return limiter
}

// 5 requests per minute, burst of 3
var limiter = NewIPRateLimiter(rate.Every(12*time.Second), 3)

func rateLimitMiddleware(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		ip := r.RemoteAddr
		if !limiter.GetLimiter(ip).Allow() {
			log.Printf("Rate limit exceeded for IP: %s", ip)
			w.Header().Set("Retry-After", "60")
			http.Error(w, "Too many requests", http.StatusTooManyRequests)
			return
		}
		next(w, r)
	}
}

func loginHandler(w http.ResponseWriter, r *http.Request) {
	var req LoginRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	var storedHash string
	err := db.QueryRow("SELECT password_hash FROM users WHERE username = $1", req.Username).Scan(&storedHash)
	if err != nil {
		log.Printf("Failed login attempt for user: %s from IP: %s", req.Username, r.RemoteAddr)
		json.NewEncoder(w).Encode(LoginResponse{Message: "Invalid credentials"})
		return
	}

	if bcrypt.CompareHashAndPassword([]byte(storedHash), []byte(req.Password)) != nil {
		log.Printf("Failed login attempt for user: %s from IP: %s", req.Username, r.RemoteAddr)
		json.NewEncoder(w).Encode(LoginResponse{Message: "Invalid credentials"})
		return
	}

	log.Printf("Successful login for user: %s from IP: %s", req.Username, r.RemoteAddr)
	token := generateToken(req.Username)
	json.NewEncoder(w).Encode(LoginResponse{Token: token, Message: "Success"})
}

func main() {
	http.HandleFunc("/login", rateLimitMiddleware(loginHandler))
	http.ListenAndServe(":8080", nil)
}
```

**Key Security Controls**:
- **Per-IP rate limiting**: Limits each IP to 5 login attempts per minute using token bucket algorithm
- **Retry-After header**: Informs clients when they can retry, following RFC 6585
- **Audit logging**: All failed and successful attempts logged with IP and username for forensic analysis

Distributed attacks require multiple layers of defense. Per-IP rate limiting alone won't stop botnets with millions of IPs. You need username-based limiting, progressive delays, account lockout, and behavioral analysis.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/rand"
	"database/sql"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"os"
	"strings"
	"time"

	"github.com/go-redis/redis/v8"
	"golang.org/x/crypto/bcrypt"
	_ "github.com/lib/pq"
)

var (
	db          *sql.DB
	redisClient *redis.Client
	ctx         = context.Background()
)

type LoginRequest struct {
	Username string `json:"username"`
	Password string `json:"password"`
}

type LoginResponse struct {
	Token     string `json:"token,omitempty"`
	Message   string `json:"message"`
	RetryIn   int    `json:"retry_in,omitempty"`
	Locked    bool   `json:"locked,omitempty"`
}

type RateLimitConfig struct {
	IPLimit        int           // Max attempts per IP
	IPWindow       time.Duration // Time window for IP
	UserLimit      int           // Max attempts per username
	UserWindow     time.Duration // Time window for username
	GlobalLimit    int           // Global requests per second
	LockoutLimit   int           // Failures before lockout
	LockoutDuration time.Duration // How long to lock account
}

var config = RateLimitConfig{
	IPLimit:         20,
	IPWindow:        time.Hour,
	UserLimit:       5,
	UserWindow:      15 * time.Minute,
	GlobalLimit:     100,
	LockoutLimit:    10,
	LockoutDuration: 30 * time.Minute,
}

// Multi-layer rate limiting using Redis
type MultiLayerRateLimiter struct {
	redis *redis.Client
}

func (m *MultiLayerRateLimiter) CheckIPLimit(ip string) (bool, int, error) {
	key := fmt.Sprintf("ratelimit:ip:%s", ip)
	count, err := m.redis.Incr(ctx, key).Result()
	if err != nil {
		return false, 0, err
	}
	if count == 1 {
		m.redis.Expire(ctx, key, config.IPWindow)
	}
	remaining := config.IPLimit - int(count)
	return count <= int64(config.IPLimit), remaining, nil
}

func (m *MultiLayerRateLimiter) CheckUsernameLimit(username string) (bool, int, error) {
	key := fmt.Sprintf("ratelimit:user:%s", strings.ToLower(username))
	count, err := m.redis.Incr(ctx, key).Result()
	if err != nil {
		return false, 0, err
	}
	if count == 1 {
		m.redis.Expire(ctx, key, config.UserWindow)
	}
	remaining := config.UserLimit - int(count)
	return count <= int64(config.UserLimit), remaining, nil
}

func (m *MultiLayerRateLimiter) IsAccountLocked(username string) (bool, time.Duration, error) {
	key := fmt.Sprintf("lockout:user:%s", strings.ToLower(username))
	ttl, err := m.redis.TTL(ctx, key).Result()
	if err != nil {
		return false, 0, err
	}
	return ttl > 0, ttl, nil
}

func (m *MultiLayerRateLimiter) IncrementFailure(username string) (int, error) {
	key := fmt.Sprintf("failures:user:%s", strings.ToLower(username))
	count, err := m.redis.Incr(ctx, key).Result()
	if err != nil {
		return 0, err
	}
	m.redis.Expire(ctx, key, config.UserWindow)

	if count >= int64(config.LockoutLimit) {
		lockKey := fmt.Sprintf("lockout:user:%s", strings.ToLower(username))
		m.redis.Set(ctx, lockKey, "locked", config.LockoutDuration)
		log.Printf("SECURITY: Account locked due to %d failed attempts: %s", count, username)
	}
	return int(count), nil
}

func (m *MultiLayerRateLimiter) ResetFailures(username string) {
	key := fmt.Sprintf("failures:user:%s", strings.ToLower(username))
	m.redis.Del(ctx, key)
}

var rateLimiter *MultiLayerRateLimiter

// Security headers middleware
func securityHeaders(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("X-Content-Type-Options", "nosniff")
		w.Header().Set("X-Frame-Options", "DENY")
		w.Header().Set("Content-Security-Policy", "default-src 'none'")
		w.Header().Set("Cache-Control", "no-store")
		next(w, r)
	}
}

// Get real IP from reverse proxy
func getRealIP(r *http.Request) string {
	forwarded := r.Header.Get("X-Forwarded-For")
	if forwarded != "" {
		ips := strings.Split(forwarded, ",")
		return strings.TrimSpace(ips[0])
	}
	realIP := r.Header.Get("X-Real-IP")
	if realIP != "" {
		return realIP
	}
	return strings.Split(r.RemoteAddr, ":")[0]
}

func loginHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	ip := getRealIP(r)
	requestID := generateRequestID()

	var req LoginRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		log.Printf("[%s] Invalid request body from IP: %s", requestID, ip)
		w.WriteHeader(http.StatusBadRequest)
		json.NewEncoder(w).Encode(LoginResponse{Message: "Invalid request"})
		return
	}

	// Layer 1: Check IP rate limit
	allowed, remaining, err := rateLimiter.CheckIPLimit(ip)
	if err != nil {
		log.Printf("[%s] Rate limit check error: %v", requestID, err)
		w.WriteHeader(http.StatusInternalServerError)
		json.NewEncoder(w).Encode(LoginResponse{Message: "Service unavailable"})
		return
	}
	w.Header().Set("X-RateLimit-Remaining", fmt.Sprintf("%d", remaining))

	if !allowed {
		log.Printf("[%s] SECURITY: IP rate limit exceeded: %s", requestID, ip)
		w.Header().Set("Retry-After", "3600")
		w.WriteHeader(http.StatusTooManyRequests)
		json.NewEncoder(w).Encode(LoginResponse{
			Message: "Too many requests from this IP",
			RetryIn: 3600,
		})
		return
	}

	// Layer 2: Check account lockout
	locked, ttl, _ := rateLimiter.IsAccountLocked(req.Username)
	if locked {
		log.Printf("[%s] SECURITY: Attempted login to locked account: %s from IP: %s", requestID, req.Username, ip)
		w.WriteHeader(http.StatusTooManyRequests)
		json.NewEncoder(w).Encode(LoginResponse{
			Message: "Account temporarily locked",
			Locked:  true,
			RetryIn: int(ttl.Seconds()),
		})
		return
	}

	// Layer 3: Check username rate limit
	allowed, _, _ = rateLimiter.CheckUsernameLimit(req.Username)
	if !allowed {
		log.Printf("[%s] SECURITY: Username rate limit exceeded: %s from IP: %s", requestID, req.Username, ip)
		w.Header().Set("Retry-After", "900")
		w.WriteHeader(http.StatusTooManyRequests)
		json.NewEncoder(w).Encode(LoginResponse{
			Message: "Too many login attempts for this account",
			RetryIn: 900,
		})
		return
	}

	// Verify credentials
	var storedHash string
	var userID int
	err = db.QueryRow("SELECT id, password_hash FROM users WHERE username = $1", req.Username).Scan(&userID, &storedHash)
	if err != nil {
		rateLimiter.IncrementFailure(req.Username)
		logSecurityEvent(requestID, "LOGIN_FAILED", req.Username, ip, "user_not_found")
		// Constant-time delay to prevent username enumeration
		bcrypt.CompareHashAndPassword([]byte("$2a$10$dummy"), []byte(req.Password))
		w.WriteHeader(http.StatusUnauthorized)
		json.NewEncoder(w).Encode(LoginResponse{Message: "Invalid credentials"})
		return
	}

	if bcrypt.CompareHashAndPassword([]byte(storedHash), []byte(req.Password)) != nil {
		failures, _ := rateLimiter.IncrementFailure(req.Username)
		logSecurityEvent(requestID, "LOGIN_FAILED", req.Username, ip, fmt.Sprintf("wrong_password_attempt_%d", failures))
		w.WriteHeader(http.StatusUnauthorized)
		json.NewEncoder(w).Encode(LoginResponse{Message: "Invalid credentials"})
		return
	}

	// Successful login
	rateLimiter.ResetFailures(req.Username)
	token, _ := generateSecureToken()

	logSecurityEvent(requestID, "LOGIN_SUCCESS", req.Username, ip, "")

	// Store session
	storeSession(token, userID, ip)

	json.NewEncoder(w).Encode(LoginResponse{
		Token:   token,
		Message: "Login successful",
	})
}

func logSecurityEvent(requestID, eventType, username, ip, details string) {
	log.Printf("[%s] SECURITY_EVENT: type=%s user=%s ip=%s details=%s", 
		requestID, eventType, username, ip, details)
	// In production: send to SIEM (Splunk, ELK, etc.)
}

func generateRequestID() string {
	b := make([]byte, 8)
	rand.Read(b)
	return hex.EncodeToString(b)
}

func generateSecureToken() (string, error) {
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	return hex.EncodeToString(b), nil
}

func storeSession(token string, userID int, ip string) {
	key := fmt.Sprintf("session:%s", token)
	redisClient.HSet(ctx, key, map[string]interface{}{
		"user_id":    userID,
		"ip":         ip,
		"created_at": time.Now().Unix(),
	})
	redisClient.Expire(ctx, key, 24*time.Hour)
}

func main() {
	// Initialize Redis
	redisClient = redis.NewClient(&redis.Options{
		Addr:     os.Getenv("REDIS_URL"),
		Password: os.Getenv("REDIS_PASSWORD"),
	})
	rateLimiter = &MultiLayerRateLimiter{redis: redisClient}

	// Initialize DB
	var err error
	db, err = sql.Open("postgres", os.Getenv("DATABASE_URL"))
	if err != nil {
		log.Fatal(err)
	}

	http.HandleFunc("/login", securityHeaders(loginHandler))

	log.Println("Server starting on :8080")
	http.ListenAndServe(":8080", nil)
}
