const express = require('express');
const bcrypt = require('bcrypt');
const { Pool } = require('pg');
const rateLimit = require('express-rate-limit');
const RedisStore = require('rate-limit-redis');
const Redis = require('ioredis');
const crypto = require('crypto');
const winston = require('winston');

const app = express();
app.use(express.json());

// Structured logging for security events
const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  defaultMeta: { service: 'auth-service' },
  transports: [
    new winston.transports.File({ filename: 'security-events.log' }),
    new winston.transports.Console()
  ]
});

const pool = new Pool({ connectionString: process.env.DATABASE_URL });
const redis = new Redis(process.env.REDIS_URL);

// Configuration constants
const CONFIG = {
  MAX_FAILED_ATTEMPTS: 5,
  LOCKOUT_DURATION_MINUTES: 15,
  PROGRESSIVE_DELAY_BASE: 1000, // 1 second base delay
  MFA_COOLDOWN_SECONDS: 30,
  MFA_MAX_REQUESTS_PER_HOUR: 10,
  MFA_CODE_EXPIRY_MINUTES: 5
};

// IP-based rate limiter (soft limit - delays, doesn't block)
const ipRateLimiter = rateLimit({
  windowMs: 60 * 1000, // 1 minute
  max: 20,
  standardHeaders: true,
  store: new RedisStore({ sendCommand: (...args) => redis.call(...args) }),
  handler: (req, res) => {
    securityLogger.warn({
      event: 'rate_limit_exceeded',
      ip: req.ip,
      endpoint: req.path,
      userAgent: req.get('User-Agent')
    });
    res.status(429).json({
      error: 'Too many requests',
      retryAfter: 60
    });
  }
});

// Progressive delay based on failed attempts (prevents brute force without lockout)
async function getProgressiveDelay(username) {
  const key = `failed_attempts:${username}`;
  const attempts = parseInt(await redis.get(key)) || 0;

  if (attempts === 0) return 0;

  // Exponential backoff: 1s, 2s, 4s, 8s, 16s, max 30s
  const delay = Math.min(
    CONFIG.PROGRESSIVE_DELAY_BASE * Math.pow(2, attempts - 1),
    30000
  );

  return delay;
}

async function recordFailedAttempt(username, ip) {
  const userKey = `failed_attempts:${username}`;
  const ipKey = `failed_ip:${ip}`;

  // Increment counters with expiry
  await redis.multi()
    .incr(userKey)
    .expire(userKey, CONFIG.LOCKOUT_DURATION_MINUTES * 60)
    .incr(ipKey)
    .expire(ipKey, CONFIG.LOCKOUT_DURATION_MINUTES * 60)
    .exec();

  const userAttempts = parseInt(await redis.get(userKey));
  const ipAttempts = parseInt(await redis.get(ipKey));

  return { userAttempts, ipAttempts };
}

async function clearFailedAttempts(username) {
  await redis.del(`failed_attempts:${username}`);
}

// Check if IP is suspicious (high failure rate across multiple accounts)
async function isIPSuspicious(ip) {
  const ipAttempts = parseInt(await redis.get(`failed_ip:${ip}`)) || 0;
  return ipAttempts > 20; // Suspicious if >20 failed attempts from same IP
}

// MFA rate limiting - prevents MFA bombing
async function canRequestMFA(userId) {
  const cooldownKey = `mfa_cooldown:${userId}`;
  const hourlyKey = `mfa_hourly:${userId}`;

  // Check cooldown (minimum 30 seconds between requests)
  const lastRequest = await redis.get(cooldownKey);
  if (lastRequest) {
    const secondsSinceLastRequest = Math.floor((Date.now() - parseInt(lastRequest)) / 1000);
    if (secondsSinceLastRequest < CONFIG.MFA_COOLDOWN_SECONDS) {
      return {
        allowed: false,
        reason: 'cooldown',
        waitSeconds: CONFIG.MFA_COOLDOWN_SECONDS - secondsSinceLastRequest
      };
    }
  }

  // Check hourly limit
  const hourlyCount = parseInt(await redis.get(hourlyKey)) || 0;
  if (hourlyCount >= CONFIG.MFA_MAX_REQUESTS_PER_HOUR) {
    return {
      allowed: false,
      reason: 'hourly_limit',
      message: 'Maximum MFA requests reached. Please contact support.'
    };
  }

  return { allowed: true };
}

async function recordMFARequest(userId) {
  const cooldownKey = `mfa_cooldown:${userId}`;
  const hourlyKey = `mfa_hourly:${userId}`;

  await redis.multi()
    .set(cooldownKey, Date.now(), 'EX', CONFIG.MFA_COOLDOWN_SECONDS)
    .incr(hourlyKey)
    .expire(hourlyKey, 3600) // 1 hour expiry
    .exec();
}

// Main login endpoint
app.post('/api/login', ipRateLimiter, async (req, res) => {
  const { username, password } = req.body;
