        event: 'locked_account_attempt',
        userId: user.id,
        username: username,
        ip: clientIP
      });
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const validPassword = await bcrypt.compare(password, user.password_hash);

    if (!validPassword) {
      const { userAttempts } = await recordFailedAttempt(username, clientIP);

      securityLogger.info({
        event: 'login_failed',
        reason: 'invalid_password',
        userId: user.id,
