```java
import org.springframework.web.bind.annotation.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import io.github.bucket4j.Bandwidth;
import io.github.bucket4j.Bucket;
import io.github.bucket4j.Bucket4j;
import io.github.bucket4j.Refill;
import javax.servlet.http.HttpServletRequest;
import java.time.Duration;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@RestController
@RequestMapping("/api/auth")
public class SecureAuthController {

    private static final Logger logger = LoggerFactory.getLogger(SecureAuthController.class);

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private BCryptPasswordEncoder passwordEncoder;

    // Rate limiting: 5 attempts per minute per IP
    private final Map<String, Bucket> ipBuckets = new ConcurrentHashMap<>();

    // Rate limiting: 3 attempts per minute per username
    private final Map<String, Bucket> usernameBuckets = new ConcurrentHashMap<>();

    @PostMapping("/login")
    public ResponseEntity<?> login(
            @RequestBody LoginRequest request,
            HttpServletRequest httpRequest) {

        String clientIp = getClientIp(httpRequest);
        String username = request.getUsername();

        // RATE LIMIT CHECK - IP-based
        Bucket ipBucket = ipBuckets.computeIfAbsent(clientIp, this::createIpBucket);
        if (!ipBucket.tryConsume(1)) {
            logger.warn("Rate limit exceeded for IP: {}", clientIp);
            return ResponseEntity.status(429)
                .body(Map.of("error", "Too many requests. Try again later."));
        }

        // RATE LIMIT CHECK - Username-based (prevents distributed attacks)
        Bucket userBucket = usernameBuckets.computeIfAbsent(username, this::createUserBucket);
        if (!userBucket.tryConsume(1)) {
            logger.warn("Rate limit exceeded for username: {} from IP: {}", username, clientIp);
            return ResponseEntity.status(429)
                .body(Map.of("error", "Too many requests. Try again later."));
        }

        User user = userRepository.findByUsername(username);

        // Constant-time comparison to prevent timing attacks
        boolean validCredentials = user != null && 
            passwordEncoder.matches(request.getPassword(), user.getPasswordHash());

        if (validCredentials) {
            logger.info("Successful login for user: {} from IP: {}", username, clientIp);
            String token = generateJwtToken(user);
            return ResponseEntity.ok(new AuthResponse(token));
        }

        logger.warn("Failed login attempt for user: {} from IP: {}", username, clientIp);
        // Generic error message to prevent user enumeration
        return ResponseEntity.status(401).body(Map.of("error", "Invalid credentials"));
    }

    private Bucket createIpBucket(String ip) {
        return Bucket4j.builder()
            .addLimit(Bandwidth.classic(5, Refill.intervally(5, Duration.ofMinutes(1))))
            .build();
    }

    private Bucket createUserBucket(String username) {
        return Bucket4j.builder()
            .addLimit(Bandwidth.classic(3, Refill.intervally(3, Duration.ofMinutes(1))))
            .build();
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private String generateJwtToken(User user) {
        // JWT generation logic
        return "jwt_token_here";
    }
}
```

**Key Security Controls**:
- **IP-based rate limiting**: 5 attempts per minute prevents automated attacks from single sources
- **Username-based rate limiting**: 3 attempts per minute prevents distributed attacks targeting specific accounts
- **Security logging**: Failed attempts are logged with IP and username for incident response
- **Generic error messages**: Same response for invalid username/password prevents user enumeration

