```java
import org.springframework.web.bind.annotation.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.data.redis.core.StringRedisTemplate;
import org.springframework.stereotype.Service;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import javax.servlet.http.HttpServletRequest;
import java.time.Duration;
import java.util.Map;
import java.util.concurrent.TimeUnit;

@RestController
@RequestMapping("/api/auth")
public class ProductionAuthController {

    private static final Logger logger = LoggerFactory.getLogger(ProductionAuthController.class);
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private BCryptPasswordEncoder passwordEncoder;

    @Autowired
    private DistributedRateLimiter rateLimiter;

    @Autowired
    private AccountLockoutService lockoutService;

    @Autowired
    private ThreatIntelligenceService threatIntel;

    @Autowired
    private SecurityMetricsService metricsService;

    @PostMapping("/login")
    public ResponseEntity<?> login(
            @RequestBody LoginRequest request,
            HttpServletRequest httpRequest) {

        String clientIp = getClientIp(httpRequest);
        String username = sanitizeUsername(request.getUsername());
        String userAgent = httpRequest.getHeader("User-Agent");
        String requestId = generateRequestId();

        // LAYER 1: Check threat intelligence blocklist
        if (threatIntel.isBlockedIp(clientIp)) {
            securityLogger.warn("[{}] Blocked IP attempted login: {} for user: {}", 
                requestId, clientIp, username);
            metricsService.incrementBlockedRequests();
            return ResponseEntity.status(403)
                .body(Map.of("error", "Access denied"));
        }

        // LAYER 2: Check account lockout status
        if (lockoutService.isAccountLocked(username)) {
            Duration remainingLockout = lockoutService.getRemainingLockoutTime(username);
            securityLogger.warn("[{}] Login attempt on locked account: {} from IP: {}", 
                requestId, username, clientIp);
            return ResponseEntity.status(423)
                .body(Map.of(
                    "error", "Account temporarily locked",
                    "retry_after", remainingLockout.getSeconds()
                ));
        }

        // LAYER 3: Distributed rate limiting (IP-based)
        RateLimitResult ipLimit = rateLimiter.checkIpLimit(clientIp);
        if (!ipLimit.isAllowed()) {
            securityLogger.warn("[{}] IP rate limit exceeded: {} attempts from {}", 
                requestId, ipLimit.getAttemptCount(), clientIp);
            metricsService.incrementRateLimitedRequests("ip");

            // Add to watchlist for repeated violations
            if (ipLimit.getAttemptCount() > 50) {
                threatIntel.addToWatchlist(clientIp, "excessive_login_attempts");
            }

            return ResponseEntity.status(429)
                .header("Retry-After", String.valueOf(ipLimit.getRetryAfter()))
                .body(Map.of(
                    "error", "Too many requests",
                    "retry_after", ipLimit.getRetryAfter()
                ));
        }

        // LAYER 4: Distributed rate limiting (Username-based)
        RateLimitResult userLimit = rateLimiter.checkUsernameLimit(username);
        if (!userLimit.isAllowed()) {
            securityLogger.warn("[{}] Username rate limit exceeded for: {} from IP: {}", 
                requestId, username, clientIp);
            metricsService.incrementRateLimitedRequests("username");
            return ResponseEntity.status(429)
                .header("Retry-After", String.valueOf(userLimit.getRetryAfter()))
                .body(Map.of(
                    "error", "Too many requests",
                    "retry_after", userLimit.getRetryAfter()
                ));
        }

        // LAYER 5: Progressive delay based on recent failures
        int recentFailures = rateLimiter.getRecentFailures(clientIp, username);
        if (recentFailures > 2) {
            long delayMs = Math.min(1000 * (long) Math.pow(2, recentFailures - 2), 30000);
            try {
                Thread.sleep(delayMs);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }

        // AUTHENTICATION LOGIC
        User user = userRepository.findByUsername(username);
        boolean validCredentials = user != null && 
            passwordEncoder.matches(request.getPassword(), user.getPasswordHash());

        if (validCredentials) {
            // Success: reset counters and log
            rateLimiter.recordSuccess(clientIp, username);
            lockoutService.resetFailedAttempts(username);

            securityLogger.info("[{}] Successful login: user={}, ip={}, ua={}", 
                requestId, username, clientIp, userAgent);
            metricsService.incrementSuccessfulLogins();

            String token = generateJwtToken(user);
            return ResponseEntity.ok(new AuthResponse(token));
        }

        // Failure: record and potentially lock
        rateLimiter.recordFailure(clientIp, username);
        int failedAttempts = lockoutService.recordFailedAttempt(username);

        securityLogger.warn("[{}] Failed login: user={}, ip={}, attempt={}, ua={}", 
            requestId, username, clientIp, failedAttempts, userAgent);
        metricsService.incrementFailedLogins();

        // Lock account after 5 consecutive failures
        if (failedAttempts >= 5) {
            Duration lockoutDuration = Duration.ofMinutes(15 * (failedAttempts / 5));
            lockoutService.lockAccount(username, lockoutDuration);
            securityLogger.error("[{}] Account locked: {} for {} minutes due to {} failed attempts", 
                requestId, username, lockoutDuration.toMinutes(), failedAttempts);
        }

        return ResponseEntity.status(401)
            .body(Map.of("error", "Invalid credentials"));
    }

    private String getClientIp(HttpServletRequest request) {
        // Handle proxy chains properly
        String[] headers = {"X-Forwarded-For", "X-Real-IP", "CF-Connecting-IP"};
        for (String header : headers) {
            String value = request.getHeader(header);
            if (value != null && !value.isEmpty()) {
                return value.split(",")[0].trim();
            }
        }
        return request.getRemoteAddr();
    }

    private String sanitizeUsername(String username) {
        if (username == null) return "";
        return username.toLowerCase().trim().replaceAll("[^a-z0-9@._-]", "");
    }

    private String generateRequestId() {
        return java.util.UUID.randomUUID().toString().substring(0, 8);
    }

    private String generateJwtToken(User user) {
        return "jwt_token_here";
    }
}

@Service
public class DistributedRateLimiter {

    @Autowired
    private StringRedisTemplate redis;

    private static final int IP_LIMIT = 20;           // 20 attempts per minute per IP
    private static final int USERNAME_LIMIT = 5;      // 5 attempts per minute per username
    private static final int GLOBAL_LIMIT = 1000;     // 1000 attempts per minute globally

    public RateLimitResult checkIpLimit(String ip) {
        String key = "rate:ip:" + ip;
        return checkLimit(key, IP_LIMIT, 60);
    }

    public RateLimitResult checkUsernameLimit(String username) {
        String key = "rate:user:" + username;
        return checkLimit(key, USERNAME_LIMIT, 60);
    }

    private RateLimitResult checkLimit(String key, int limit, int windowSeconds) {
        Long count = redis.opsForValue().increment(key);
        if (count == 1) {
            redis.expire(key, windowSeconds, TimeUnit.SECONDS);
        }

        boolean allowed = count <= limit;
        long ttl = redis.getExpire(key, TimeUnit.SECONDS);

        return new RateLimitResult(allowed, count.intValue(), ttl > 0 ? ttl : windowSeconds);
    }

    public void recordFailure(String ip, String username) {
        String failKey = "failures:" + ip + ":" + username;
        redis.opsForValue().increment(failKey);
        redis.expire(failKey, 15, TimeUnit.MINUTES);
    }

    public void recordSuccess(String ip, String username) {
        String failKey = "failures:" + ip + ":" + username;
        redis.delete(failKey);
    }

    public int getRecentFailures(String ip, String username) {
        String failKey = "failures:" + ip + ":" + username;
        String value = redis.opsForValue().get(failKey);
        return value != null ? Integer.parseInt(value) : 0;
    }
}

@Service
public class AccountLockoutService {

    @Autowired
    private StringRedisTemplate redis;

    public boolean isAccountLocked(String username) {
        return redis.hasKey("lockout:" + username);
    }

    public Duration getRemainingLockoutTime(String username) {
        Long ttl = redis.getExpire("lockout:" + username, TimeUnit.SECONDS);
        return Duration.ofSeconds(ttl != null && ttl > 0 ? ttl : 0);
    }

    public int recordFailedAttempt(String username) {
        String key = "failed_attempts:" + username;
        Long count = redis.opsForValue().increment(key);
        redis.expire(key, 1, TimeUnit.HOURS);
        return count.intValue();
    }

    public void resetFailedAttempts(String username) {
        redis.delete("failed_attempts:" + username);
    }

    public void lockAccount(String username, Duration duration) {
        redis.opsForValue().set("lockout:" + username, "locked", duration);
    }
}
