package main

import (
	"database/sql"
	"encoding/json"
	"net/http"
	"sync"
	"time"

	"golang.org/x/crypto/bcrypt"
	"golang.org/x/time/rate"
	_ "github.com/lib/pq"
)

type RateLimiter struct {
	limiters map[string]*rate.Limiter
	mu       sync.RWMutex
	rate     rate.Limit
	burst    int
}

func NewRateLimiter(r rate.Limit, b int) *RateLimiter {
	return &RateLimiter{
		limiters: make(map[string]*rate.Limiter),
		rate:     r,
		burst:    b,
	}
}

func (rl *RateLimiter) GetLimiter(key string) *rate.Limiter {
	rl.mu.Lock()
	defer rl.mu.Unlock()

	limiter, exists := rl.limiters[key]
	if !exists {
		limiter = rate.NewLimiter(rl.rate, rl.burst)
		rl.limiters[key] = limiter
	}
	return limiter
}

var (
	db          *sql.DB
	ipLimiter   = NewRateLimiter(rate.Every(time.Second), 5)     // 5 requests/second per IP
	userLimiter = NewRateLimiter(rate.Every(time.Minute), 5)    // 5 attempts/minute per username
)

func secureLoginHandler(w http.ResponseWriter, r *http.Request) {
	clientIP := r.RemoteAddr

	// DEFENSE 1: IP-based rate limiting
	if !ipLimiter.GetLimiter(clientIP).Allow() {
		w.Header().Set("Retry-After", "60")
		http.Error(w, "Too many requests", http.StatusTooManyRequests)
		return
	}

	var req LoginRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// DEFENSE 2: Username-based rate limiting
	if !userLimiter.GetLimiter(req.Username).Allow() {
		// SECURE: Generic error prevents enumeration
		json.NewEncoder(w).Encode(LoginResponse{Success: false, Error: "Invalid credentials"})
		return
	}

	var hashedPassword string
	err := db.QueryRow("SELECT password_hash FROM users WHERE username = $1", req.Username).Scan(&hashedPassword)

	// DEFENSE 3: Constant-time comparison even for non-existent users
	if err != nil {
		bcrypt.CompareHashAndPassword([]byte("$2a$10$dummyhashvalue"), []byte(req.Password))
		json.NewEncoder(w).Encode(LoginResponse{Success: false, Error: "Invalid credentials"})
		return
	}

	if err := bcrypt.CompareHashAndPassword([]byte(hashedPassword), []byte(req.Password)); err != nil {
		json.NewEncoder(w).Encode(LoginResponse{Success: false, Error: "Invalid credentials"})
		return
	}

	token := generateToken(req.Username)
	json.NewEncoder(w).Encode(LoginResponse{Success: true, Token: token})
}
