**Key Security Controls**:
- **IP-based rate limiting**: Restricts requests per IP address to prevent automated attacks
- **Username-based rate limiting**: Limits attempts per account to prevent targeted brute force
- **Generic error messages**: Same response for invalid username/password prevents enumeration
- **Constant-time comparison**: Prevents timing attacks that reveal valid usernames

Excellent questions. Distributed attacks require multiple defense layers, and NAT situations need intelligent identification. Production systems use device fingerprinting, CAPTCHA escalation, and global rate limiting across all IPs.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/sha256"
	"database/sql"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"strings"
	"time"

	"github.com/go-redis/redis/v8"
	"golang.org/x/crypto/bcrypt"
	_ "github.com/lib/pq"
)

type AuthConfig struct {
	IPRateLimit        int           `json:"ip_rate_limit"`        // requests per window
	UserRateLimit      int           `json:"user_rate_limit"`      // attempts per window
	GlobalRateLimit    int           `json:"global_rate_limit"`    // total login attempts
	WindowDuration     time.Duration `json:"window_duration"`
	LockoutThreshold   int           `json:"lockout_threshold"`
	LockoutDuration    time.Duration `json:"lockout_duration"`
	CaptchaThreshold   int           `json:"captcha_threshold"`
	SuspiciousIPScore  int           `json:"suspicious_ip_score"`
}

type AuthService struct {
	db     *sql.DB
	redis  *redis.Client
	config AuthConfig
	logger *slog.Logger
}

func NewAuthService(db *sql.DB, redisClient *redis.Client) *AuthService {
	return &AuthService{
		db:    db,
		redis: redisClient,
		config: AuthConfig{
			IPRateLimit:       10,
			UserRateLimit:     5,
			GlobalRateLimit:   1000,
			WindowDuration:    time.Minute,
			LockoutThreshold:  10,
			LockoutDuration:   time.Hour,
			CaptchaThreshold:  3,
			SuspiciousIPScore: 50,
		},
		logger: slog.New(slog.NewJSONHandler(os.Stdout, nil)),
	}
}

type LoginContext struct {
	ClientIP       string
	DeviceFingerprint string
	Username       string
	UserAgent      string
	RequestID      string
}

// DEFENSE 1: Multi-dimensional rate limiting with Redis
func (s *AuthService) checkRateLimits(ctx context.Context, lc *LoginContext) (bool, string) {
	pipe := s.redis.Pipeline()
	now := time.Now().Unix()
	windowKey := now / int64(s.config.WindowDuration.Seconds())

	// IP-based rate limit
	ipKey := fmt.Sprintf("ratelimit:ip:%s:%d", lc.ClientIP, windowKey)
	ipCount := pipe.Incr(ctx, ipKey)
	pipe.Expire(ctx, ipKey, s.config.WindowDuration)

	// Username-based rate limit
	userKey := fmt.Sprintf("ratelimit:user:%s:%d", lc.Username, windowKey)
	userCount := pipe.Incr(ctx, userKey)
	pipe.Expire(ctx, userKey, s.config.WindowDuration)

	// Device fingerprint rate limit (handles NAT gracefully)
	deviceKey := fmt.Sprintf("ratelimit:device:%s:%d", lc.DeviceFingerprint, windowKey)
	deviceCount := pipe.Incr(ctx, deviceKey)
	pipe.Expire(ctx, deviceKey, s.config.WindowDuration)

	// Global rate limit (protects against distributed attacks)
	globalKey := fmt.Sprintf("ratelimit:global:login:%d", windowKey)
	globalCount := pipe.Incr(ctx, globalKey)
	pipe.Expire(ctx, globalKey, s.config.WindowDuration)

	if _, err := pipe.Exec(ctx); err != nil {
		s.logger.Error("Redis pipeline error", "error", err)
		return false, "service_unavailable"
	}

	if ipCount.Val() > int64(s.config.IPRateLimit) {
		s.logger.Warn("IP rate limit exceeded",
			"ip", lc.ClientIP,
			"count", ipCount.Val(),
			"request_id", lc.RequestID)
		return false, "ip_rate_limited"
	}

	if userCount.Val() > int64(s.config.UserRateLimit) {
		s.logger.Warn("User rate limit exceeded",
			"username", lc.Username,
			"count", userCount.Val(),
			"request_id", lc.RequestID)
		return false, "user_rate_limited"
	}

	if globalCount.Val() > int64(s.config.GlobalRateLimit) {
		s.logger.Error("Global rate limit exceeded - possible attack",
			"count", globalCount.Val())
		return false, "global_rate_limited"
	}

	return true, ""
}

// DEFENSE 2: Account lockout with progressive delays
func (s *AuthService) checkAccountLockout(ctx context.Context, username string) (bool, time.Duration) {
	lockoutKey := fmt.Sprintf("lockout:user:%s", username)
	lockoutTTL := s.redis.TTL(ctx, lockoutKey).Val()

	if lockoutTTL > 0 {
		return true, lockoutTTL
	}

	failuresKey := fmt.Sprintf("failures:user:%s", username)
	failures, _ := s.redis.Get(ctx, failuresKey).Int()

	if failures >= s.config.LockoutThreshold {
		// Progressive lockout: doubles with each threshold breach
		lockoutTime := s.config.LockoutDuration * time.Duration(failures/s.config.LockoutThreshold)
		s.redis.Set(ctx, lockoutKey, "1", lockoutTime)
		return true, lockoutTime
	}

	return false, 0
}

// DEFENSE 3: CAPTCHA requirement based on suspicious behavior
func (s *AuthService) requiresCaptcha(ctx context.Context, lc *LoginContext) bool {
	failuresKey := fmt.Sprintf("failures:user:%s", lc.Username)
	failures, _ := s.redis.Get(ctx, failuresKey).Int()

	if failures >= s.config.CaptchaThreshold {
		return true
	}

	// Check IP reputation score
	ipScoreKey := fmt.Sprintf("reputation:ip:%s", lc.ClientIP)
	score, _ := s.redis.Get(ctx, ipScoreKey).Int()

	return score >= s.config.SuspiciousIPScore
}

// DEFENSE 4: Device fingerprinting for NAT-friendly identification
func (s *AuthService) generateDeviceFingerprint(r *http.Request) string {
	components := []string{
		r.Header.Get("User-Agent"),
		r.Header.Get("Accept-Language"),
		r.Header.Get("Accept-Encoding"),
		r.Header.Get("Sec-CH-UA"),
		r.Header.Get("Sec-CH-UA-Platform"),
	}

	hash := sha256.Sum256([]byte(strings.Join(components, "|")))
	return hex.EncodeToString(hash[:16])
}

// DEFENSE 5: Suspicious IP detection and scoring
func (s *AuthService) updateIPReputation(ctx context.Context, ip string, success bool) {
	ipScoreKey := fmt.Sprintf("reputation:ip:%s", ip)

	if success {
		// Successful login decreases suspicion
		s.redis.DecrBy(ctx, ipScoreKey, 10)
	} else {
		// Failed login increases suspicion
		s.redis.IncrBy(ctx, ipScoreKey, 5)
	}

	// Expire reputation after 24 hours
	s.redis.Expire(ctx, ipScoreKey, 24*time.Hour)
}

func (s *AuthService) LoginHandler(w http.ResponseWriter, r *http.Request) {
	ctx := r.Context()

	// Extract client context
	lc := &LoginContext{
		ClientIP:          s.getRealClientIP(r),
		DeviceFingerprint: s.generateDeviceFingerprint(r),
		UserAgent:         r.Header.Get("User-Agent"),
		RequestID:         r.Header.Get("X-Request-ID"),
	}

	var req LoginRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}
	lc.Username = req.Username

	// DEFENSE 1: Multi-dimensional rate limiting
	allowed, reason := s.checkRateLimits(ctx, lc)
	if !allowed {
		s.logger.Warn("Rate limited",
			"reason", reason,
			"ip", lc.ClientIP,
			"username", lc.Username,
			"request_id", lc.RequestID)

		w.Header().Set("Retry-After", "60")
		w.Header().Set("X-RateLimit-Reason", reason)
		http.Error(w, "Too many requests", http.StatusTooManyRequests)
		return
	}

	// DEFENSE 2: Account lockout check
	locked, remaining := s.checkAccountLockout(ctx, lc.Username)
	if locked {
		s.logger.Warn("Account locked",
			"username", lc.Username,
			"remaining", remaining,
			"ip", lc.ClientIP)

		w.Header().Set("Retry-After", fmt.Sprintf("%d", int(remaining.Seconds())))
		json.NewEncoder(w).Encode(LoginResponse{
			Success: false,
			Error:   "Account temporarily locked. Please try again later.",
		})
		return
	}

	// DEFENSE 3: CAPTCHA requirement
	if s.requiresCaptcha(ctx, lc) {
		captchaToken := r.Header.Get("X-Captcha-Token")
		if !s.verifyCaptcha(captchaToken) {
			json.NewEncoder(w).Encode(map[string]interface{}{
				"success":          false,
				"captcha_required": true,
				"captcha_site_key": os.Getenv("CAPTCHA_SITE_KEY"),
			})
			return
		}
	}

	// Perform authentication
	success := s.authenticate(ctx, lc, req.Password)

	// DEFENSE 5: Update IP reputation
	s.updateIPReputation(ctx, lc.ClientIP, success)

	if !success {
		s.recordFailedAttempt(ctx, lc)
		// Generic error - no enumeration
		json.NewEncoder(w).Encode(LoginResponse{
			Success: false,
			Error:   "Invalid credentials",
		})
		return
	}

	// Clear failure counters on success
	s.clearFailedAttempts(ctx, lc.Username)

	token := s.generateSecureToken(lc.Username)

	s.logger.Info("Successful login",
		"username", lc.Username,
		"ip", lc.ClientIP,
		"device", lc.DeviceFingerprint,
		"request_id", lc.RequestID)

	json.NewEncoder(w).Encode(LoginResponse{Success: true, Token: token})
}

func (s *AuthService) getRealClientIP(r *http.Request) string {
	// Check X-Forwarded-For with validation
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		ips := strings.Split(xff, ",")
		if len(ips) > 0 {
			return strings.TrimSpace(ips[0])
		}
	}

	// Check X-Real-IP
	if xri := r.Header.Get("X-Real-IP"); xri != "" {
		return xri
	}

	return strings.Split(r.RemoteAddr, ":")[0]
}

func (s *AuthService) authenticate(ctx context.Context, lc *LoginContext, password string) bool {
	var hashedPassword string
	err := s.db.QueryRowContext(ctx,
		"SELECT password_hash FROM users WHERE username = $1 AND active = true",
		lc.Username).Scan(&hashedPassword)

	// Constant-time: always do bcrypt comparison
	dummyHash := "$2a$12$LQv3c1yqBWVHxkd0LHAkCOYz6TtxMQJqhN8/X4.Vl5nHKyBjKLlqW"
	if err != nil {
		bcrypt.CompareHashAndPassword([]byte(dummyHash), []byte(password))
		return false
	}

	return bcrypt.CompareHashAndPassword([]byte(hashedPassword), []byte(password)) == nil
}

func (s *AuthService) recordFailedAttempt(ctx context.Context, lc *LoginContext) {
	failuresKey := fmt.Sprintf("failures:user:%s", lc.Username)
	s.redis.Incr(ctx, failuresKey)
	s.redis.Expire(ctx, failuresKey, 24*time.Hour)

	s.logger.Warn("Failed login attempt",
		"username", lc.Username,
		"ip", lc.ClientIP,
		"device", lc.DeviceFingerprint,
		"user_agent", lc.UserAgent,
		"request_id", lc.RequestID)
}

func (s *AuthService) clearFailedAttempts(ctx context.Context, username string) {
	s.redis.Del(ctx, fmt.Sprintf("failures:user:%s", username))
}

func (s *AuthService) verifyCaptcha(token string) bool {
	// Implement CAPTCHA verification (e.g., reCAPTCHA, hCaptcha)
	return token != ""
}

func (s *AuthService) generateSecureToken(username string) string {
	// Implement JWT or session token generation
	return "secure-token-placeholder"
}
```

**Defense in Depth Layers**:

1. **Multi-dimensional rate limiting**: IP, username, device fingerprint, and global limits work together to catch different attack patterns

2. **Progressive account lockout**: Escalating lockout durations deter persistent attackers while allowing legitimate recovery

3. **Device fingerprinting**: Identifies unique clients behind shared IPs (NAT), allowing stricter IP limits without blocking legitimate users

4. **CAPTCHA escalation**: Only triggered after suspicious behavior, balancing security with user experience

5. **IP reputation scoring**: Tracks suspicious IPs across time, detecting distributed attacks

**Additional Protections**:

- **Redis-based distributed rate limiting**: Works across multiple application instances
- **Constant-time authentication**: Prevents timing-based username enumeration
- **Structured logging**: All security events logged with correlation IDs for incident response
- **Graceful degradation**: Service remains available even if Redis fails temporarily
- **Header-based client identification**: Uses Sec-CH-UA and other client hints for fingerprinting

A login API without rate limiting is critically vulnerable to brute-force attacks, credential stuffing, and denial of service. Attackers can automate thousands of login attempts per second to crack passwords or validate stolen credentials.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');
const db = require('./database');

const app = express();
app.use(express.json());

// VULNERABLE: No rate limiting on login endpoint
app.post('/api/login', async (req, res) => {
  const { username, password } = req.body;

  try {
    const user = await db.findUserByUsername(username);

    if (!user) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const validPassword = await bcrypt.compare(password, user.passwordHash);

    if (!validPassword) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const token = jwt.sign({ userId: user.id }, process.env.JWT_SECRET, {
      expiresIn: '1h'
    });

    res.json({ token, user: { id: user.id, username: user.username } });
  } catch (error) {
    res.status(500).json({ error: 'Login failed' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```bash
# Credential stuffing attack using hydra
hydra -L usernames.txt -P passwords.txt https://target.com http-post-form "/api/login:username=^USER^&password=^PASS^:Invalid credentials"

# Or using curl in a loop for brute-force
for password in $(cat rockyou.txt); do
  curl -X POST https://target.com/api/login \
    -H "Content-Type: application/json" \
    -d "{\"username\":\"admin\",\"password\":\"$password\"}"
done
```

**Why This Is Dangerous**:
- Attackers can attempt unlimited login requests per second
- Credential stuffing attacks can validate millions of stolen username/password combinations
- Brute-force attacks can crack weak passwords in hours
- Server resources can be exhausted leading to denial of service
- No visibility into attack attempts for security monitoring

**SECURE VERSION**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');
const rateLimit = require('express-rate-limit');
const RedisStore = require('rate-limit-redis');
const Redis = require('ioredis');
const db = require('./database');
const logger = require('./logger');

const app = express();
app.use(express.json());

// Redis client for distributed rate limiting
const redisClient = new Redis(process.env.REDIS_URL);

// SECURE: Rate limiter for login endpoint
const loginLimiter = rateLimit({
  store: new RedisStore({
    sendCommand: (...args) => redisClient.call(...args),
  }),
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // 5 attempts per window
  message: { error: 'Too many login attempts, please try again later' },
  standardHeaders: true,
  legacyHeaders: false,
  keyGenerator: (req) => {
    // Rate limit by IP AND username to prevent distributed attacks
    return `${req.ip}:${req.body.username || 'unknown'}`;
  },
  handler: (req, res, next, options) => {
    logger.warn('Rate limit exceeded', {
      ip: req.ip,
      username: req.body.username,
      endpoint: '/api/login'
    });
    res.status(options.statusCode).json(options.message);
  }
});

// SECURE: Apply rate limiting to login endpoint
app.post('/api/login', loginLimiter, async (req, res) => {
  const { username, password } = req.body;

  // Input validation
  if (!username || !password || typeof username !== 'string' || typeof password !== 'string') {
    return res.status(400).json({ error: 'Invalid request format' });
  }

  try {
    const user = await db.findUserByUsername(username);

    // Use constant-time comparison to prevent timing attacks
    if (!user) {
      // Perform dummy bcrypt compare to prevent timing-based user enumeration
      await bcrypt.compare(password, '$2b$10$invalidhashtopreventtiming');
      logger.info('Failed login attempt - user not found', { username, ip: req.ip });
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const validPassword = await bcrypt.compare(password, user.passwordHash);

    if (!validPassword) {
      logger.info('Failed login attempt - invalid password', { username, ip: req.ip });
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Successful login - log for audit trail
    logger.info('Successful login', { userId: user.id, username, ip: req.ip });

    const token = jwt.sign({ userId: user.id }, process.env.JWT_SECRET, {
      expiresIn: '1h'
    });

    res.json({ token, user: { id: user.id, username: user.username } });
  } catch (error) {
    logger.error('Login error', { error: error.message, username, ip: req.ip });
    res.status(500).json({ error: 'Login failed' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Rate limiting**: Maximum 5 login attempts per 15 minutes per IP+username combination
- **Distributed tracking**: Redis-backed store works across multiple server instances
- **Logging**: All login attempts (successful and failed) are logged for security monitoring
- **Timing attack prevention**: Dummy bcrypt comparison prevents user enumeration
- **Input validation**: Rejects malformed requests before processing

Sophisticated attackers use distributed botnets with thousands of unique IPs, making simple IP-based rate limiting insufficient. Production systems need layered defenses including account-level rate limiting, progressive delays, CAPTCHA challenges, device fingerprinting, and anomaly detection.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');
const rateLimit = require('express-rate-limit');
const RedisStore = require('rate-limit-redis');
const Redis = require('ioredis');
const svgCaptcha = require('svg-captcha');
const crypto = require('crypto');
const geoip = require('geoip-lite');
const db = require('./database');
const logger = require('./logger');
const alerting = require('./alerting');

const app = express();
app.use(express.json());

const redisClient = new Redis(process.env.REDIS_URL);

// Layer 1: Global rate limiter (prevents DDoS)
const globalLimiter = rateLimit({
  store: new RedisStore({ sendCommand: (...args) => redisClient.call(...args) }),
  windowMs: 60 * 1000,
  max: 100,
  message: { error: 'Service temporarily unavailable' },
  skip: (req) => req.ip === '127.0.0.1' // Skip for health checks
});

// Layer 2: Strict login rate limiter per IP
const ipLoginLimiter = rateLimit({
  store: new RedisStore({ sendCommand: (...args) => redisClient.call(...args) }),
  windowMs: 15 * 60 * 1000,
  max: 10,
  keyGenerator: (req) => `login:ip:${req.ip}`,
  standardHeaders: true
});

// Layer 3: Account-level rate limiting (defeats IP rotation)
class AccountRateLimiter {
  constructor(redis) {
    this.redis = redis;
  }

  async checkAndIncrement(username) {
    const key = `login:account:${username.toLowerCase()}`;
    const attempts = await this.redis.incr(key);

    if (attempts === 1) {
      await this.redis.expire(key, 3600); // 1 hour window
    }

    return {
      attempts,
      blocked: attempts > 10,
      requiresCaptcha: attempts > 3,
      progressiveDelay: Math.min(Math.pow(2, attempts - 1) * 1000, 30000)
    };
  }

  async reset(username) {
    await this.redis.del(`login:account:${username.toLowerCase()}`);
  }

  async getFailedAttempts(username) {
    return parseInt(await this.redis.get(`login:account:${username.toLowerCase()}`)) || 0;
  }
}

const accountLimiter = new AccountRateLimiter(redisClient);

// Layer 4: Device fingerprinting
class DeviceFingerprint {
  static generate(req) {
    const components = [
      req.headers['user-agent'] || '',
      req.headers['accept-language'] || '',
      req.headers['accept-encoding'] || '',
      req.ip
    ];
    return crypto.createHash('sha256').update(components.join('|')).digest('hex').substring(0, 16);
  }

  static async isKnownDevice(redis, userId, fingerprint) {
    const knownDevices = await redis.smembers(`user:${userId}:devices`);
    return knownDevices.includes(fingerprint);
  }

  static async registerDevice(redis, userId, fingerprint) {
    await redis.sadd(`user:${userId}:devices`, fingerprint);
    await redis.expire(`user:${userId}:devices`, 30 * 24 * 60 * 60); // 30 days
  }
}

// Layer 5: Anomaly detection
class AnomalyDetector {
  static async analyze(redis, username, req) {
    const geo = geoip.lookup(req.ip);
    const country = geo ? geo.country : 'UNKNOWN';
    const lastLoginKey = `user:${username}:lastlogin`;
    const lastLogin = JSON.parse(await redis.get(lastLoginKey) || '{}');

    const anomalies = [];

    // Check for impossible travel
    if (lastLogin.country && lastLogin.country !== country) {
      const timeDiff = Date.now() - (lastLogin.timestamp || 0);
      if (timeDiff < 3600000) { // Less than 1 hour
        anomalies.push('impossible_travel');
      }
    }

    // Check for unusual hour
    const hour = new Date().getHours();
    if (lastLogin.typicalHours && !lastLogin.typicalHours.includes(hour)) {
      anomalies.push('unusual_time');
    }

    return {
      country,
      anomalies,
      riskScore: anomalies.length * 25
    };
  }
}

// CAPTCHA middleware
const captchaRequired = async (req, res, next) => {
  const { username, captchaToken, captchaId } = req.body;

  if (!username) return next();

  const accountStatus = await accountLimiter.checkAndIncrement(username);
  req.accountStatus = accountStatus;

  if (accountStatus.blocked) {
    logger.warn('Account temporarily locked', { username, ip: req.ip });
    return res.status(429).json({
      error: 'Account temporarily locked due to too many failed attempts',
      retryAfter: 3600
    });
  }

  if (accountStatus.requiresCaptcha) {
    if (!captchaToken || !captchaId) {
      const captcha = svgCaptcha.create({ size: 6, noise: 3 });
      const captchaKey = crypto.randomUUID();
      await redisClient.setex(`captcha:${captchaKey}`, 300, captcha.text);

      return res.status(428).json({
        error: 'CAPTCHA required',
        captchaId: captchaKey,
        captchaSvg: captcha.data
      });
    }

    const storedCaptcha = await redisClient.get(`captcha:${captchaId}`);
    if (!storedCaptcha || storedCaptcha.toLowerCase() !== captchaToken.toLowerCase()) {
      return res.status(400).json({ error: 'Invalid CAPTCHA' });
    }

    await redisClient.del(`captcha:${captchaId}`);
  }

  // Apply progressive delay
  if (accountStatus.progressiveDelay > 0) {
    await new Promise(resolve => setTimeout(resolve, accountStatus.progressiveDelay));
  }

  next();
};

app.use(globalLimiter);

app.post('/api/login', ipLoginLimiter, captchaRequired, async (req, res) => {
  const { username, password } = req.body;
  const fingerprint = DeviceFingerprint.generate(req);

  if (!username || !password) {
    return res.status(400).json({ error: 'Username and password required' });
  }

  try {
    const user = await db.findUserByUsername(username);

    if (!user) {
      await bcrypt.compare(password, '$2b$10$dummyhashfortimingattak');
      logger.info('Login failed - user not found', {
        username,
        ip: req.ip,
        fingerprint,
        attempts: req.accountStatus?.attempts
      });
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const validPassword = await bcrypt.compare(password, user.passwordHash);

    if (!validPassword) {
      logger.info('Login failed - invalid password', {
        userId: user.id,
        username,
        ip: req.ip,
        fingerprint,
        attempts: req.accountStatus?.attempts
      });

      // Alert on high failure count
      if (req.accountStatus?.attempts >= 8) {
        await alerting.send('security', {
          type: 'brute_force_suspected',
          username,
          attempts: req.accountStatus.attempts,
          ip: req.ip
        });
      }

      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // SUCCESS - Reset rate limits and analyze
    await accountLimiter.reset(username);

    const anomalyResult = await AnomalyDetector.analyze(redisClient, username, req);
    const isKnownDevice = await DeviceFingerprint.isKnownDevice(redisClient, user.id, fingerprint);

    // Require additional verification for risky logins
    if (anomalyResult.riskScore >= 50 || !isKnownDevice) {
      const verificationToken = crypto.randomUUID();
      await redisClient.setex(`verify:${verificationToken}`, 600, JSON.stringify({
        userId: user.id,
        fingerprint,
        reason: isKnownDevice ? 'anomaly_detected' : 'new_device'
      }));

      logger.warn('Additional verification required', {
        userId: user.id,
        reason: anomalyResult.anomalies,
        isKnownDevice,
        riskScore: anomalyResult.riskScore
      });

      return res.status(403).json({
        error: 'Additional verification required',
        verificationRequired: true,
        method: 'email', // or 'sms', 'totp'
        token: verificationToken
      });
    }

    // Register device and update login metadata
    await DeviceFingerprint.registerDevice(redisClient, user.id, fingerprint);
    await redisClient.set(`user:${username}:lastlogin`, JSON.stringify({
      timestamp: Date.now(),
      country: anomalyResult.country,
      ip: req.ip
    }));

    logger.info('Login successful', {
      userId: user.id,
      username,
      ip: req.ip,
      fingerprint,
      country: anomalyResult.country
    });

    const token = jwt.sign(
      { userId: user.id, fingerprint },
      process.env.JWT_SECRET,
      { expiresIn: '1h' }
    );

    res.json({
      token,
      user: { id: user.id, username: user.username }
    });

  } catch (error) {
    logger.error('Login system error', { error: error.message, stack: error.stack });
    res.status(500).json({ error: 'Authentication service unavailable' });
  }
});

// Health check for monitoring
app.get('/health', (req, res) => {
  res.json({ status: 'healthy', timestamp: new Date().toISOString() });
});

app.listen(3000);
```

